SELECT log_time, log_description 
FROM process_logs 
WHERE log_time = (SELECT MAX(log_time) FROM process_logs);

SELECT process_type
FROM process_runs
WHERE run_id = 0;

SELECT DISTINCT run_status
FROM process_runs
ORDER BY run_status;

SELECT DISTINCT process_type
FROM process_runs
WHERE run_status = 'completed';

SELECT bioreactor_name, location
FROM bioreactors
WHERE installation_date >= DATE('now', '-1 year');

SELECT bioreactor_name
FROM bioreactors
ORDER BY bioreactor_name;

SELECT COUNT(*) AS num_continuous_bioreactors
FROM bioreactors
WHERE type = 'Continuous';

SELECT DISTINCT model
FROM bioreactors
WHERE bioreactor_id IN (
    SELECT bioreactor_id
    FROM process_runs
);

SELECT bioreactor_name
FROM bioreactors
WHERE capacity = (SELECT MAX(capacity) FROM bioreactors);

SELECT bioreactor_name, capacity, type, MAX(capacity) OVER () AS max_capacity
FROM bioreactors
WHERE capacity > 1200.0;

SELECT bioreactor_name, capacity
FROM bioreactors
WHERE bioreactor_id = 0;
